  ('cpa-moex-00671', 'cpa', 'cpa-moex-109-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '按一般稅額計算之營業人購買下列貨物或勞務，依加值型及非加值型營業稅法及相關法規規定， 下列何者不得申報進項稅額扣抵銷項稅額？', '["供捐贈政府機關做為急難救助之用品", "員工業務出差住宿飯店之費用", "招待經銷商用餐之費用", "購買貨車"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:08+00:00", "source_pdf_sha1": "7c1b78aca74b", "answer_pdf_sha1": "fa0e8eb61f87", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
