  ('cpa-moex-00673', 'cpa', 'cpa-moex-109-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '下列敘述何者不符合加值型及非加值型營業稅法之規定？', '["因信託行為成立，委託人依信託契約，將信託財產移轉與受託人，應按該信託財產之時價，作 為視為銷售貨物之銷售額並申報繳納營業稅", "委託代銷之委託人運送貨物交付受託人時，應依代銷契約所約定代銷貨物價格，作為視為銷售 貨物之銷售額", "受託代購時，受託人應依代購貨物實際購買價格，作為視為銷售貨物之銷售額", "委託代銷之受託人銷售貨物與買受人時，應依代銷契約所約定代銷貨物價格，作為視為銷售貨 物之銷售額"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:08+00:00", "source_pdf_sha1": "7c1b78aca74b", "answer_pdf_sha1": "fa0e8eb61f87", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00674', 'cpa', 'cpa-moex-109-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依加值型及非加值型營業稅法規定，下列何者免徵營業稅？', '["白金項鍊", "公車儲值卡", "電話卡", "代銷郵票之勞務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:08+00:00", "source_pdf_sha1": "7c1b78aca74b", "answer_pdf_sha1": "fa0e8eb61f87", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00675', 'cpa', 'cpa-moex-109-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '甲公司於109年5月1日向乙公司承租辦公室一間，每月租金70,000元（含營業稅），另付押金 210,000元，假設當年1月1日郵政定期儲金一年期固定利率為2%，甲公司此項租賃依加值型及 非加值型營業稅法規定，109年5月之進項稅額為若干？（甲公司及乙公司均為一般稅額計算之 營業人）', '["3,333元", "3,350元", "3,469元", "3,533元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:08+00:00", "source_pdf_sha1": "7c1b78aca74b", "answer_pdf_sha1": "fa0e8eb61f87", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00676', 'cpa', 'cpa-moex-109-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依土地稅法規定，都市計畫公共設施保留地，未做任何使用並與使用中之土地隔離者，其地價稅 之稅率為何？', '["10‰", "6‰", "2‰", "免徵"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:08+00:00", "source_pdf_sha1": "7c1b78aca74b", "answer_pdf_sha1": "fa0e8eb61f87", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00677', 'cpa', 'cpa-moex-109-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依稅捐稽徵法規定，納稅義務人對核准延期或分期繳納之稅捐，未如期繳納者，稅捐稽徵機關應 如何處理？', '["未如期繳納任何一期稅捐，應就未繳清之餘額稅款，發單通知納稅義務人，限10日內一次全部 繳清", "未如期繳納稅捐累計達三期者，應就未繳清之餘額稅款，發單通知納稅義務人，限10日內一次 全部繳清", "未如期繳納稅捐累計達三期者，應就未繳清之餘額稅款，發單通知納稅義務人，限分三次繳清", "逕行移送強制執行"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:08+00:00", "source_pdf_sha1": "7c1b78aca74b", "answer_pdf_sha1": "fa0e8eb61f87", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00678', 'cpa', 'cpa-moex-109-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依稅捐稽徵法規定，下列有關繳納通知文書之敘述何者正確？', '["納稅義務人如發現繳納通知文書有計算錯誤，應於繳納期間屆滿之日起 30 日內，向稅捐稽徵 機關申請查對更正", "應受送達人在服役中，無父母或配偶者，得委託戶籍地兵役課代為送達", "為稽徵土地稅或房屋稅所發之各種文書，得以使用人為應受送達人", "納稅義務人為全體公同共有人者，繳款書應向全體公同共有人送達"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:08+00:00", "source_pdf_sha1": "7c1b78aca74b", "answer_pdf_sha1": "fa0e8eb61f87", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00679', 'cpa', 'cpa-moex-109-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依稅捐稽徵法規定，有關加徵滯納金之敘述，下列何者正確？', '["徵收至納稅人繳納稅款止", "逾30日仍未繳納，移送強制執行", "逾45日仍未繳納，移送強制執行", "逾2個月仍未繳納，移送強制執行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:08+00:00", "source_pdf_sha1": "7c1b78aca74b", "answer_pdf_sha1": "fa0e8eb61f87", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
